
(function(){
  if (window.__osauth_listener_installed__) return;
  window.__osauth_listener_installed__ = true;

  function applyTokensFromStorage(){
    try{
      var t = localStorage.getItem('osauth.tokens.v1');
      if (t){ return true; }
      var c = localStorage.getItem('osauth.code.v1');
      if (c){ return true; }
    }catch(e){}
    return false;
  }

  function handleMessage(ev){
    try{
      if (ev.origin !== window.location.origin) return;
      var d = ev.data || {};
      if (d && typeof d === 'object' && /^osauth:/.test(d.type||'')){
        if (d.type === 'osauth:error'){
          try{
            console.warn('[OSAUTH] error:', d.error, d.error_description || '');
          }catch(e){}
          // Displaying a warning instead of a reload to keep the UI stable
          alert('Authentication error: ' + (d.error || 'Unknown error'));
          return;
        }
        if (d.type === 'osauth:code' || d.type === 'osauth:done'){
          // Tokens or code are already saved by callback. Just refresh UI.
          if (!applyTokensFromStorage()){
            console.warn('Tokens were not found, fallback to refresh');
          } else {
            // Log success and let the page continue without reload
            console.log('Authentication successful, tokens applied');
          }
        }
      }
    }catch(e){}
  }

  try{ window.addEventListener('message', handleMessage, false); }catch(e){}
})();
